export default async function handler(req, res) {
  // CORS headers — allow any origin for the public web app
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  res.setHeader('X-Fengshui-Api-Version', '2026-06-14-gemini-front-only-v1');

  if (req.method === 'OPTIONS') return res.status(200).end();
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' });

  const { photoB64, photoMime, interiorB64, interiorMime, type, dir, env, details = {} } = req.body;

  if (!photoB64 || !type || !dir || !env) {
    return res.status(400).json({ error: 'Missing required fields' });
  }

  // ── Input validation: image size & format ──
  const MAX_B64_BYTES = 8 * 1024 * 1024; // ~6MB raw image
  if (photoB64.length > MAX_B64_BYTES) {
    return res.status(413).json({ error: 'ภาพหน้าบ้านใหญ่เกินไป กรุณาลดขนาดก่อนส่ง (ไม่เกิน 6MB)' });
  }
  if (interiorB64 && interiorB64.length > MAX_B64_BYTES) {
    return res.status(413).json({ error: 'ภาพภายในบ้านใหญ่เกินไป กรุณาลดขนาดก่อนส่ง (ไม่เกิน 6MB)' });
  }
  const ALLOWED_MIME = ['image/jpeg','image/jpg','image/png','image/webp','image/gif'];
  if (!ALLOWED_MIME.includes(photoMime)) {
    return res.status(400).json({ error: 'รองรับเฉพาะไฟล์ภาพ JPEG, PNG, WEBP เท่านั้น' });
  }

  // ── Rate limiting — Vercel KV (persistent) with in-memory fallback ──
  const ip = (req.headers['x-forwarded-for'] || req.socket?.remoteAddress || 'unknown')
    .split(',')[0].trim();
  const WINDOW_SEC = 600; // 10 minutes
  const MAX_CALLS = 10;

  let rateLimited = false;
  let retryAfter = WINDOW_SEC;

  try {
    // Try Vercel KV first (requires KV_REST_API_URL + KV_REST_API_TOKEN env vars)
    if (process.env.KV_REST_API_URL && process.env.KV_REST_API_TOKEN) {
      const kvKey = `fs_rate:${ip}`;
      const kvUrl = `${process.env.KV_REST_API_URL}/pipeline`;
      const kvToken = process.env.KV_REST_API_TOKEN;

      // INCR + EXPIRE in one pipeline call (no external dependency needed)
      const pipeline = [
        ['INCR', kvKey],
        ['TTL', kvKey],
      ];
      const kvRes = await fetch(kvUrl, {
        method: 'POST',
        headers: { Authorization: `Bearer ${kvToken}`, 'Content-Type': 'application/json' },
        body: JSON.stringify(pipeline),
      });
      if (kvRes.ok) {
        const [[,count],[,ttl]] = await kvRes.json();
        if (count === 1) {
          // First request in window — set expiry
          await fetch(`${process.env.KV_REST_API_URL}/expire/${kvKey}/${WINDOW_SEC}`, {
            method: 'POST',
            headers: { Authorization: `Bearer ${kvToken}` },
          });
        }
        retryAfter = ttl > 0 ? ttl : WINDOW_SEC;
        if (count > MAX_CALLS) rateLimited = true;
      }
    } else {
      // Fallback: in-memory (resets on cold start — acceptable for low traffic)
      if (!global._fsRateMap) global._fsRateMap = new Map();
      const now = Date.now();
      const WINDOW_MS = WINDOW_SEC * 1000;
      const entry = global._fsRateMap.get(ip) || { count: 0, start: now };
      if (now - entry.start > WINDOW_MS) { entry.count = 0; entry.start = now; }
      entry.count++;
      global._fsRateMap.set(ip, entry);
      if (global._fsRateMap.size > 5000) {
        for (const [k, v] of global._fsRateMap) {
          if (now - v.start > WINDOW_MS) global._fsRateMap.delete(k);
        }
      }
      retryAfter = Math.ceil((WINDOW_MS - (Date.now() - entry.start)) / 1000);
      if (entry.count > MAX_CALLS) rateLimited = true;
    }
  } catch (rateErr) {
    // Rate limit check failed — allow request through (fail open)
    console.error('Rate limit check error:', rateErr.message);
  }

  if (rateLimited) {
    res.setHeader('Retry-After', retryAfter);
    return res.status(429).json({ error: 'ส่งคำขอบ่อยเกินไป กรุณารอสักครู่แล้วลองใหม่', retryAfter });
  }

  const GEMINI_API_KEY = process.env.GEMINI_API_KEY || process.env.GOOGLE_API_KEY;
  const GEMINI_MODEL = process.env.GEMINI_MODEL || 'gemini-2.5-flash-lite';
  if (!GEMINI_API_KEY) {
    return res.status(500).json({ error: 'Gemini API key not configured' });
  }

  const userText = `ข้อมูลบ้านที่ผู้ใช้ให้มา:
- ประเภท/รูปแบบที่ผู้ใช้เลือก: ${type}
- ทิศหน้าบ้าน: ${dir}
- สภาพแวดล้อม: ${env}
- ปัญหาที่เจ้าของบ้านเลือก: ${details.pain || 'ไม่ได้ระบุ'}
- บ้านนี้ใช้งานแบบไหน: ${details.usage || 'ไม่ได้ระบุ'}
- อยู่บ้านนี้มากี่ปี: ${details.years || 'ไม่ได้ระบุ'}

รอบนี้ให้วิเคราะห์เฉพาะหน้าบ้านเท่านั้น ใช้ทิศหน้าบ้านแบบคร่าวๆ ตามที่ผู้ใช้เลือก ไม่ต้องลงลึกถึงองศา
ให้ผูกผลวิเคราะห์กับปัญหาที่เจ้าของบ้านเลือก เช่น เงินเก็บไม่อยู่ งานติดขัด คนในบ้านเครียด บ้านรกง่าย หรือไม่อยากกลับบ้าน โดยใช้คำว่า อาจ, มักพบร่วมกับ, มีแนวโน้ม เมื่อยังไม่สามารถยืนยันจากภาพได้
ถ้าภาพหน้าบ้านเห็นรายละเอียด เช่น ประตู ทางเดิน รั้ว พื้น ชาน ทางลาด ของวาง ตู้ไฟ สายไฟ หลังคา ความทึบ ความโปร่ง ให้ดึงสิ่งนั้นมาเขียนโดยตรง ห้ามตอบแบบกว้างๆ
ห้ามพูดถึงภายในบ้านในผลหลัก หากต้องใส่ช่อง interiorPart ให้ระบุเพียงว่ารอบนี้โฟกัสหน้าบ้านเท่านั้น`;

  const jsonInstructions = `ตอบกลับเป็น JSON object เท่านั้น ห้ามมี markdown ห้ามมีคำอธิบายนอก JSON

schema ที่ต้องใช้:
{
  "score": 0,
  "headline": "",
  "scoreLabel": "",
  "typeCheck": "",
  "frontPart": "",
  "interiorPart": "",
  "observationsText": "",
  "goodText": "",
  "badText": "",
  "fixText": "",
  "omen": "",
  "needsExpert": true
}

กติกาการเขียน:
- observationsText ใส่ 5-6 ข้อ คั่นด้วย | แต่ละข้อเป็น "หัวข้อ: รายละเอียด"
- goodText ใส่ 3 ข้อ คั่นด้วย |
- badText ใส่ 4 ข้อ คั่นด้วย |
- fixText ใส่ 7-8 ข้อ คั่นด้วย | ข้อ 1-2 เป็นสิ่งที่ทำเองได้ทันที ข้อถัดไปเป็นจุดที่ควรให้ซินแสดูหน้างาน
- รายละเอียดแต่ละข้อใช้ bullet สั้น ๆ ด้วยเครื่องหมาย • 2-4 bullet
- ห้ามใส่เลขลำดับในหัวข้อ เช่น "จุดเด่น 1" หรือ "สิ่งที่เห็นจากภาพ 1"
- ห้ามใช้คำว่า AI ในคำตอบ
- ถ้าต้องตรวจเพิ่ม ให้เขียนว่า "จุดนี้ให้ซินแสดูหน้างานเพื่อเช็กของจริงได้"
- ถ้าภาพหน้าบ้านดูดีจริง ให้ให้คะแนนสูงตามสมควร ไม่สร้างปัญหาเกินจริง`;

  let timeout;
  try {
    const controller = new AbortController();
    timeout = setTimeout(() => controller.abort(), 56000);

    const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${encodeURIComponent(GEMINI_MODEL)}:generateContent?key=${encodeURIComponent(GEMINI_API_KEY)}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      signal: controller.signal,
      body: JSON.stringify({
        systemInstruction: {
          parts: [{
            text: frontOnlySystemPrompt + '\n\nกติกาเพิ่มเติม: วิเคราะห์จากภาพหน้าบ้านจริงในคำขอนี้โดยตรง อย่าตอบว่าระบบอ่านภาพไม่ได้ถ้าภาพยังมองเห็นบ้านได้ชัด ถ้าบ้านดูดีให้พูดว่าดีและให้คะแนนสูงตามสมควร ไม่ต้องพยายามหาปัญหาเกินจริง เขียนแบบมือโปร ตรง ใช้งานได้จริง ไม่อวยเกินจริง ไม่ขายแข็ง ทุกข้อสำคัญต้องอ้างสิ่งที่เห็นในภาพก่อนเสมอ'
          }]
        },
        generationConfig: {
          temperature: 0.25,
          topP: 0.9,
          maxOutputTokens: 2600,
          responseMimeType: 'application/json'
        },
        contents: [{
          role: 'user',
          parts: [
            { text: 'ภาพนี้คือภาพหน้าบ้านจริง ให้ตรวจจากภาพโดยตรง: ประตูหลักเด่นไหม ทางเดินจากรั้วถึงประตูเปิดโล่งไหม พื้นหน้าบ้านเรียบร้อยไหม รั้วและเสาเบียดทางเข้าไหม ต้นไม้ รถ ของวาง ตู้ไฟ สายไฟ หรือของหนักบังสายตาไหม แสงและความโปร่งโดยรวมเป็นอย่างไร ถ้าบ้านดูดีให้ประเมินว่าดี ไม่ต้องสร้างปัญหาเกินจริง' },
            { inlineData: { mimeType: photoMime || 'image/jpeg', data: photoB64 } },
            { text: `${userText}

ให้เขียนผลวิเคราะห์หน้าบ้านเท่านั้น ห้ามวิเคราะห์ภายในบ้าน ห้ามพูดเหมือนเห็นพื้นที่ที่ภาพไม่ได้แสดง

แนวให้คะแนน:
- ถ้าหน้าบ้านสว่าง โปร่ง ประตูชัด ทางเดินชัด พื้นเรียบร้อย ต้นไม้จัดดี และไม่มีของบังเด่น ให้คะแนน 82-94
- ถ้าบ้านโดยรวมดีแต่มีรถ ต้นไม้ รั้ว หรือของวางบางจุดบังสายตาเล็กน้อย ให้คะแนน 76-88
- ถ้าทางเข้าไม่ชัด ทึบ รก หรือประตูหลักถูกบังจริง ให้ค่อยลดลง 45-68

เป้าหมายธุรกิจ: CTA ต้องพาคนส่งรูปเพิ่มหรือคุยต่อด้วยเหตุผลเฉพาะ เช่น ต้องดูมุมประตู/ระดับพื้น/รั้วเพิ่ม ไม่ใช่บอกว่าอ่านภาพไม่ได้

${jsonInstructions}` }
          ]
        }]
      })
    });

    if (!response.ok) {
      const err = await response.text();
      console.error('Gemini analysis error:', err);
      return res.status(502).json({ error: 'Upstream API error', detail: err });
    }

    const data = await response.json();
    const raw = (data.candidates || [])
      .flatMap(candidate => candidate?.content?.parts || [])
      .map(part => part.text || '')
      .join('')
      .trim();

    let parsed;
    let via = 'gemini_json';
    try {
      parsed = extractJson(raw);
    } catch (parseErr) {
      console.error('Invalid structured analysis:', raw.slice(0, 1800), JSON.stringify(data.candidates || []).slice(0, 1800));
      return res.status(502).json({ error: 'Invalid structured analysis', detail: parseErr.message });
    }

    const result = normalizeAiResult(parsed, false);
    return res.status(200).json({ ok: true, result, via });

  } catch (err) {
    console.error('Handler error:', err);
    if (err.name === 'AbortError') return res.status(504).json({ error: 'AI analysis timeout' });
    return res.status(500).json({ error: err.message });
  } finally {
    if (timeout) clearTimeout(timeout);
  }
}
